Here's a complete example of data-driven MSTest tests for a `PriceCalculator` class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

// --- System Under Test ---
public class PriceCalculator
{
    public decimal CalculateTotal(decimal unitPrice, int quantity)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(unitPrice);
        ArgumentOutOfRangeException.ThrowIfNegativeOrZero(quantity);
        return unitPrice * quantity;
    }

    public decimal ApplyDiscount(decimal total, decimal discountPercent)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(total);
        if (discountPercent is < 0 or > 100)
            throw new ArgumentOutOfRangeException(nameof(discountPercent));
        return total - (total * discountPercent / 100m);
    }
}

// --- Tests ---
[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ─── DataRow: inline compile-time constants ───

    [TestMethod]
    [DataRow(10.00, 1, 10.00)]
    [DataRow(10.00, 5, 50.00)]
    [DataRow(0.99, 3, 2.97)]
    [DataRow(0.00, 1, 0.00)]
    [DisplayName("CalculateTotal returns unitPrice × quantity")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00)]
    [DataRow(100.00, 10.0, 90.00)]
    [DataRow(100.00, 50.0, 50.00)]
    [DataRow(100.00, 100.0, 0.00)]
    [DataRow(59.99, 25.0, 44.9925)]
    [DisplayName("ApplyDiscount reduces total by percentage")]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        double total, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)total, (decimal)discountPercent);
        Assert.AreEqual((decimal)expected, result);
    }

    // ─── DynamicData: complex/decimal-precise test cases ───

    public static IEnumerable<object[]> CalculateTotalCases =>
    [
        [9.99m,  100, 999.00m],
        [1234.56m, 2, 2469.12m],
        [0.01m, 10000, 100.00m],
    ];

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    [DisplayName("CalculateTotal handles large/precise values")]
    public void CalculateTotal_DynamicCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal expected)
    {
        Assert.AreEqual(expected, _calculator.CalculateTotal(unitPrice, quantity));
    }

    public static IEnumerable<object[]> ApplyDiscountCases =>
    [
        [250.00m, 33.33m, 166.675m],
        [0.00m,   50.0m,  0.00m],
        [1000m,   100.0m, 0.00m],
    ];

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountCases))]
    [DisplayName("ApplyDiscount handles edge/decimal cases")]
    public void ApplyDiscount_DynamicCases_ReturnsExpected(
        decimal total, decimal discountPercent, decimal expected)
    {
        Assert.AreEqual(expected, _calculator.ApplyDiscount(total, discountPercent));
    }

    // ─── Boundary / error cases ───

    [TestMethod]
    [DataRow(-1.0, 1)]
    [DisplayName("CalculateTotal throws on negative price")]
    public void CalculateTotal_NegativePrice_Throws(double price, int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)price, qty));
    }

    [TestMethod]
    [DataRow(100.0, -1.0)]
    [DataRow(100.0, 101.0)]
    [DisplayName("ApplyDiscount throws on invalid discount")]
    public void ApplyDiscount_InvalidPercent_Throws(double total, double pct)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)total, (decimal)pct));
    }
}
```

**Key points:**

- **`[DataRow]`** — best for simple inline constants. Uses `double` params because `decimal` literals aren't compile-time constants.
- **`[DynamicData]`** — best when you need true `decimal` precision or complex object inputs. Points to a static property/method.
- Each test follows the **Arrange-Act-Assert** pattern with clear naming (`Method_Scenario_Expected`).
- Edge cases (zero, boundary, negative) and error paths are covered separately for clear failure diagnostics.
